"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { toast } from "@/components/ui/Toast";
import { validateCRP } from "@/lib/utils";

interface Step {
  id: number;
  title: string;
  description: string;
}

const STEPS: Step[] = [
  { id: 1, title: "Bem-vindo", description: "Configure seu perfil clínico" },
  { id: 2, title: "Seus dados", description: "Informações profissionais" },
  { id: 3, title: "Configurar agenda", description: "Horários e valores" },
  { id: 4, title: "IA Clínica", description: "Escolha seu modelo de IA" },
  { id: 5, title: "Telegram Bot", description: "Automação para pacientes" },
  { id: 6, title: "Tudo pronto!", description: "Revisão final" },
];

const AI_MODELS = [
  { value: "anthropic/claude-opus-4-5", label: "Claude Opus 4.5 — Máxima qualidade clínica" },
  { value: "anthropic/claude-sonnet-4-5", label: "Claude Sonnet 4.5 — Recomendado" },
  { value: "anthropic/claude-3-haiku", label: "Claude 3 Haiku — Rápido e econômico" },
  { value: "openai/gpt-4o", label: "GPT-4o — Alta precisão" },
  { value: "google/gemini-2.0-flash-001", label: "Gemini 2.0 Flash — Veloz com visão" },
];

const SPECIALTIES = [
  "Psicanálise",
  "TCC",
  "Gestalt",
  "Humanística",
  "Sistêmica",
  "Existencial",
  "ABA",
  "EMDR",
  "Mindfulness",
  "Psicodrama",
];

const SESSION_TYPES = [
  { value: "online", label: "Online (Daily.co)" },
  { value: "presencial", label: "Presencial" },
  { value: "hybrid", label: "Híbrido" },
];

export default function OnboardingPage() {
  const router = useRouter();
  const supabase = createClient();

  const [step, setStep] = useState(1);
  const [saving, setSaving] = useState(false);

  const [name, setName] = useState("");
  const [crp, setCrp] = useState("");
  const [bio, setBio] = useState("");
  const [selectedSpecialties, setSelectedSpecialties] = useState<string[]>([]);

  const [sessionPrice, setSessionPrice] = useState("200");
  const [sessionDuration, setSessionDuration] = useState("50");
  const [sessionType, setSessionType] = useState("online");
  const [timezone] = useState("America/Sao_Paulo");

  const [aiModel, setAiModel] = useState(AI_MODELS[1].value);

  const toggleSpecialty = (specialty: string) =>
    setSelectedSpecialties((prev) =>
      prev.includes(specialty)
        ? prev.filter((item) => item !== specialty)
        : [...prev, specialty]
    );

  const nextStep = () => setStep((prev) => Math.min(prev + 1, STEPS.length));
  const prevStep = () => setStep((prev) => Math.max(prev - 1, 1));

  const finish = async () => {
    if (!name.trim()) {
      toast.error("Informe seu nome");
      setStep(2);
      return;
    }
    if (!validateCRP(crp)) {
      toast.error("CRP inválido");
      setStep(2);
      return;
    }

    setSaving(true);
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser();
      if (!user) {
        router.push("/auth/login");
        return;
      }

      const { error } = await supabase
        .from("therapists")
        .update({
          name,
          crp,
          bio,
          specialties: selectedSpecialties,
          session_price: Number(sessionPrice),
          session_duration: Number(sessionDuration),
          timezone,
          ai_model: aiModel,
          onboarding_completed: true,
        })
        .eq("user_id", user.id);

      if (error) throw error;

      toast.success("Perfil configurado! Bem-vindo ao Psique.");
      router.push("/dashboard");
    } catch {
      toast.error("Erro ao salvar. Tente novamente.");
    } finally {
      setSaving(false);
    }
  };

  const currentStep = STEPS[step - 1];

  return (
    <div className="flex min-h-screen items-center justify-center bg-[var(--color-bg-base)] px-6 py-8">
      <div className="w-full max-w-[560px]">
        <div className="mb-7 text-center">
          <div className="text-[42px] font-light leading-none text-[var(--color-brand)]">Ψ</div>
          <p className="mt-1 text-[11px] uppercase tracking-[0.15em] text-[var(--color-text-muted)]">
            Passo {step} de {STEPS.length}
          </p>
        </div>

        <div className="mb-7 grid grid-cols-6 gap-2">
          {STEPS.map((item) => {
            const active = item.id <= step;
            return (
              <div
                key={item.id}
                className={`h-[3px] rounded-full transition-colors ${
                  active
                    ? "bg-[var(--color-brand)]"
                    : "bg-[var(--color-border-subtle)]"
                }`}
              />
            );
          })}
        </div>

        <div className="rounded-3xl border border-[var(--color-border-subtle)] bg-[var(--color-surface)] px-7 py-8 sm:px-9">
          <h1 className="mb-1.5 font-[family-name:var(--font-display)] text-[30px] font-light text-[var(--color-text-primary)]">
            {currentStep.title}
          </h1>
          <p className="mb-7 text-[14px] text-[var(--color-text-muted)]">{currentStep.description}</p>

          {step === 1 && (
            <div className="flex flex-col gap-4">
              {[
                {
                  title: "✦ IA Clínica",
                  text: "Resumos automáticos de sessão com Claude, GPT-4o ou Gemini",
                },
                {
                  title: "✈ Telegram Bot",
                  text: "Lembretes automáticos, agendamento e NPS para seus pacientes",
                },
                {
                  title: "📋 Prontuário LGPD",
                  text: "Evolução clínica assinada digitalmente e segura",
                },
              ].map((item) => (
                <div
                  key={item.title}
                  className="rounded-2xl border border-[var(--color-border-subtle)] bg-[var(--color-bg-elevated)] px-5 py-5"
                >
                  <div className="mb-2 text-[21px] text-[var(--color-text-primary)]">{item.title}</div>
                  <p className="text-[14px] leading-6 text-[var(--color-text-secondary)]">{item.text}</p>
                </div>
              ))}
            </div>
          )}

          {step === 2 && (
            <div className="flex flex-col gap-4">
              <Input
                label="Nome profissional"
                placeholder="Dr./Dra. Nome Sobrenome"
                value={name}
                onChange={(e) => setName(e.target.value)}
                fullWidth
              />
              <Input
                label="CRP"
                placeholder="06/123456"
                value={crp}
                onChange={(e) => setCrp(e.target.value)}
                hint="Formato: UF/número"
                fullWidth
              />

              <div>
                <label className="mb-1.5 block text-[13px] font-medium tracking-wide text-[var(--color-text-secondary)]">
                  Bio breve
                </label>
                <textarea
                  rows={3}
                  placeholder="Compartilhe um pouco sobre sua abordagem e experiência..."
                  value={bio}
                  onChange={(e) => setBio(e.target.value)}
                  className="w-full rounded-xl border border-[var(--color-border-subtle)] bg-[var(--color-surface-hover)] px-4 py-3 text-[14px] text-[var(--color-text-primary)] outline-none transition-colors placeholder:text-[var(--color-text-muted)] focus:border-[var(--color-brand)]"
                />
              </div>

              <div>
                <label className="mb-2 block text-[13px] font-medium tracking-wide text-[var(--color-text-secondary)]">
                  Especialidades (selecione as suas)
                </label>
                <div className="flex flex-wrap gap-2">
                  {SPECIALTIES.map((specialty) => {
                    const active = selectedSpecialties.includes(specialty);
                    return (
                      <button
                        key={specialty}
                        type="button"
                        onClick={() => toggleSpecialty(specialty)}
                        className={`rounded-full border px-3 py-1.5 text-[12px] transition-colors ${
                          active
                            ? "border-[var(--color-brand)] bg-[var(--color-brand)] text-[#060E09]"
                            : "border-[var(--color-border-strong)] bg-[var(--color-surface-hover)] text-[var(--color-text-secondary)] hover:border-[var(--color-border-strong)] hover:text-[var(--color-text-primary)]"
                        }`}
                      >
                        {specialty}
                      </button>
                    );
                  })}
                </div>
              </div>
            </div>
          )}

          {step === 3 && (
            <div className="flex flex-col gap-4">
              <Input
                label="Valor por sessão (R$)"
                type="number"
                value={sessionPrice}
                onChange={(e) => setSessionPrice(e.target.value)}
                prefix="R$"
                fullWidth
              />
              <Input
                label="Duração (minutos)"
                type="number"
                value={sessionDuration}
                onChange={(e) => setSessionDuration(e.target.value)}
                suffix="min"
                fullWidth
              />

              <div>
                <label className="mb-2 block text-[13px] font-medium tracking-wide text-[var(--color-text-secondary)]">
                  Modalidade
                </label>
                <div className="flex flex-wrap gap-2">
                  {SESSION_TYPES.map((type) => {
                    const active = sessionType === type.value;
                    return (
                      <button
                        key={type.value}
                        type="button"
                        onClick={() => setSessionType(type.value)}
                        className={`rounded-xl border px-3 py-2 text-[12px] transition-colors ${
                          active
                            ? "border-[var(--color-brand)] bg-[var(--color-brand-subtle)] text-[var(--color-brand)]"
                            : "border-[var(--color-border-subtle)] bg-[var(--color-surface-hover)] text-[var(--color-text-secondary)] hover:text-[var(--color-text-primary)]"
                        }`}
                      >
                        {type.label}
                      </button>
                    );
                  })}
                </div>
              </div>
            </div>
          )}

          {step === 4 && (
            <div className="flex flex-col gap-2.5">
              {AI_MODELS.map((model) => {
                const selected = aiModel === model.value;
                const [title, subtitle] = model.label.split(" — ");
                return (
                  <button
                    key={model.value}
                    type="button"
                    onClick={() => setAiModel(model.value)}
                    className={`rounded-2xl border px-4 py-3 text-left transition-colors ${
                      selected
                        ? "border-[var(--color-brand)]/50 bg-[var(--color-brand-subtle)]"
                        : "border-[var(--color-border-subtle)] bg-[var(--color-bg-elevated)] hover:border-[var(--color-border-strong)]"
                    }`}
                  >
                    <div className={`text-[13px] ${selected ? "font-semibold text-[var(--color-brand)]" : "text-[var(--color-text-primary)]"}`}>
                      {selected ? "✦ " : ""}
                      {title}
                    </div>
                    <div className="mt-0.5 text-[11px] text-[var(--color-text-muted)]">{subtitle}</div>
                  </button>
                );
              })}
            </div>
          )}

          {step === 5 && (
            <div className="flex flex-col gap-4">
              <div className="rounded-2xl border border-[var(--color-border-subtle)] bg-[var(--color-bg-elevated)] px-5 py-5 text-[14px] leading-7 text-[var(--color-text-secondary)]">
                Para configurar o Telegram Bot:
                <br />
                1. Abra o <strong className="text-[var(--color-brand)]">@BotFather</strong> no Telegram
                <br />
                2. Digite <code className="rounded bg-[var(--color-surface)] px-1.5 py-0.5 text-[12px]">/newbot</code>
                <br />
                3. Copie o <strong>TOKEN</strong> gerado
                <br />
                4. Cole nas configurações após o onboarding
              </div>

              <div className="rounded-xl border border-[rgba(82,183,136,.2)] bg-[rgba(82,183,136,.06)] px-4 py-3 text-[12px] text-[var(--color-brand)]">
                ✦ Esta etapa pode ser configurada depois em <strong>Dashboard → Telegram</strong>
              </div>
            </div>
          )}

          {step === 6 && (
            <div className="flex flex-col gap-2.5">
              {[
                { label: "Nome", value: name || "—" },
                { label: "CRP", value: crp || "—" },
                { label: "Valor", value: `R$ ${sessionPrice}` },
                { label: "Duração", value: `${sessionDuration} min` },
                {
                  label: "IA",
                  value:
                    AI_MODELS.find((model) => model.value === aiModel)?.label.split(" — ")[0] ?? "—",
                },
              ].map((item) => (
                <div
                  key={item.label}
                  className="flex items-center justify-between border-b border-[var(--color-border-subtle)] py-2.5 text-[14px]"
                >
                  <span className="text-[var(--color-text-muted)]">{item.label}</span>
                  <span className="font-medium text-[var(--color-text-primary)]">{item.value}</span>
                </div>
              ))}
            </div>
          )}

          <div className="mt-8 flex items-center justify-between gap-3">
            <Button variant="ghost" onClick={prevStep} disabled={step === 1}>
              ← Voltar
            </Button>
            {step < STEPS.length ? (
              <Button onClick={nextStep}>Próximo →</Button>
            ) : (
              <Button onClick={finish} loading={saving}>
                Começar →
              </Button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
