"use client";
import { cn } from "@/lib/utils";
import { type ButtonHTMLAttributes, forwardRef } from "react";

interface ButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: "primary" | "ghost" | "gold" | "dark" | "danger";
  size?: "sm" | "md" | "lg" | "xl";
  loading?: boolean;
  fullWidth?: boolean;
}

const VARIANTS: Record<NonNullable<ButtonProps["variant"]>, string> = {
  primary: [
    "bg-[var(--color-brand)] text-[var(--color-bg-base)] font-semibold",
    "hover:bg-[var(--color-brand-hover)] shadow-[0_4px_24px_rgba(82,183,136,.3)]",
    "hover:shadow-[0_6px_32px_rgba(82,183,136,.45)]",
  ].join(" "),
  ghost: [
    "bg-transparent text-[var(--color-text-secondary)] border border-[var(--color-border-subtle)]",
    "hover:border-[var(--color-brand)]/50 hover:text-[var(--color-text-primary)] hover:bg-[var(--color-surface-hover)]",
  ].join(" "),
  gold: [
    "bg-amber-500 text-[#0A0A06] font-semibold",
    "hover:bg-amber-400 shadow-[0_4px_20px_rgba(245,158,11,.25)]",
  ].join(" "),
  dark: [
    "bg-[var(--color-surface)] text-[var(--color-text-primary)] border border-[var(--color-border-subtle)]",
    "hover:bg-[var(--color-surface-hover)] hover:border-[var(--color-brand)]/30",
  ].join(" "),
  danger: [
    "bg-red-500/10 text-red-400 border border-red-500/20",
    "hover:bg-red-500/20 hover:border-red-500/30",
  ].join(" "),
};

const SIZES: Record<NonNullable<ButtonProps["size"]>, string> = {
  sm: "text-[13px] px-4 py-2 rounded-lg",
  md: "text-[14px] px-5 py-2.5 rounded-xl",
  lg: "text-[15px] px-6 py-3 rounded-xl",
  xl: "text-[16px] px-8 py-4 rounded-2xl",
};

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  ({ variant = "primary", size = "md", loading, fullWidth, className, disabled, children, ...props }, ref) => {
    return (
      <button
        ref={ref}
        disabled={disabled || loading}
        className={cn(
          "mag-btn relative inline-flex items-center justify-center gap-2 font-[family-name:var(--font-sans)]",
          "transition-all duration-300 cursor-pointer select-none",
          "disabled:opacity-50 disabled:cursor-not-allowed",
          "focus-visible:outline focus-visible:outline-2 focus-visible:outline-[var(--color-brand)] focus-visible:outline-offset-2",
          VARIANTS[variant],
          SIZES[size],
          fullWidth && "w-full",
          className
        )}
        {...props}
      >
        {loading ? (
          <span className="inline-block w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
        ) : null}
        {children}
      </button>
    );
  }
);

Button.displayName = "Button";
